sql:
SELECT user_id, COUNT(user_progress_id) AS progress_count
FROM user_progress
GROUP BY user_id;

SELECT UPPER(username) AS uppercase_username 
FROM users 
WHERE role = 'educator';

SELECT user_id, COUNT(*) as total_cards_reviewed
FROM review_logs
GROUP BY user_id;

SELECT COUNT(*)
FROM card_models
WHERE model_name = 'Math Basics' AND description LIKE '%addition%';

SELECT users.user_id, user_cards.card_id
FROM users
INNER JOIN user_cards ON users.user_id = user_cards.user_id;

external_knowledge:
- 'seasoned critics' refers to users who have provided more than 10 reviews; 
- 'sailing above the stormy seas of mediocrity' implies a score of at least 80, as these are considered high-quality reviews;
- 'nautical trips' is a metaphor for the number of reviews;
- 'star rating on their compass' symbolizes the average score of their reviews.

sql:
SELECT DISTINCT u.user_id, u.username
FROM users u
JOIN educator_cards ec ON u.user_id = ec.educator_id;

SELECT DISTINCT u.username, u.role
FROM users u
JOIN review_logs rl ON u.user_id = rl.user_id;
